#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int n,Q,a[N],T,tm=1,A[N],L,R,Tm,cnt[N],vis[N],ans[N],P[N<<1],pp;
struct node{int l,r,t,idx;}q[N];struct TM{int p,u,v;}t[N];
inline void ins(const int &x){--vis[cnt[x]];++vis[++cnt[x]];}
inline void del(const int &x){--vis[cnt[x]];++vis[--cnt[x]];}
inline void Back(){--Tm;int p=t[Tm].p,u=t[Tm].u;if(L<=p&&p<=R)del(a[p]),ins(a[p]=u);else a[p]=u;}
inline void Go(){int p=t[Tm].p,v=t[Tm].v;++Tm;if(L<=p&&p<=R)del(a[p]),ins(a[p]=v);else a[p]=v;}
inline int bnd(const int &k){int l(1),r(pp),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
	n=read();int nq=read();rep(1,n,i)A[i]=a[i]=P[++pp]=read();
	while(nq--)
	{
		if(read()==1){int l=read(),r=read();++Q;q[Q]=(node){l,r,tm,Q};}
		else{int p=read(),w=P[++pp]=read();t[tm++]=(TM){p,A[p],w};A[p]=w;}
	}
	std::sort(P+1,P+pp+1);pp=std::unique(P+1,P+pp+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);rep(1,tm-1,i)t[i].u=bnd(t[i].u),t[i].v=bnd(t[i].v);
	std::sort(q+1,q+Q+1,[&](const node&x,const node&y){return (x.l>>10)==(y.l>>10)?((x.r>>10)==(y.r>>10)?x.t<y.t:x.r<y.r):x.l<y.l;});
	Tm=1;L=q[1].l;R=q[1].l-1;rep(1,Q,i)
	{
		while(R<q[i].r)ins(a[++R]);while(L>q[i].l)ins(a[--L]);
		while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		while(Tm>q[i].t)Back();while(Tm<q[i].t)Go();
//		printf("%d :: ",i);rep(1,n,i)printf("%d ",a[i]);puts("");
		int res=1;while(vis[res])++res;ans[q[i].idx]=res;
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
